import { Signal } from './signal';
import { compile } from './compiler';
import { MessageFromWorklet, MessageToWorklet, Pattern, PatternName, SequencerState } from './types';
import { Synth } from './synth';
import { noteOff, noteOn } from './midi-message-constructors';
import { P_TEMPO, SAMPLE_RATE } from './constants';
import { clamp } from './helpers';
import { Module } from './module';
import { loadAiModules } from './ai-modules';

export class Msynth extends AudioWorkletProcessor implements AudioWorkletProcessorImpl {
  voiceParams: Float32Array<any>[] = [];
  voices: Synth[] = [];
  readonly sequencer = new Sequencer(this);
  aiModules: Record<string, Module<any>> = {};

  constructor() {
    super();
    this.port.onmessage = (msg: MessageEvent<MessageToWorklet>) => this.onMessage(msg.data);
  }

  sendMessage(msg: MessageFromWorklet, transferObjects: Transferable[] = []) {
    this.port.postMessage(msg, transferObjects);
  }

  onMessage(msg: MessageToWorklet) {
    switch (msg.command) {
      case 'init': {
        this.voiceParams = msg.voiceParams.map((buffer) => new Float32Array<any>(buffer));
        break;
      }
      case 'load ai modules': {
        this.aiModules = loadAiModules(msg.code);
        break;
      }
      case 'load patch': {
        console.log('worklet loading patch', msg.code);
        try {
          const { makeSignals } = compile(msg.code, this.aiModules);
          this.voices = [];
          for (let channel = 0; channel < (msg.mono ? 1 : this.voiceParams.length); channel++) {
            const allSignals: Signal[] = [];
            const outs = Signal.doCollectingNewInstances(makeSignals, allSignals);
            this.voices.push(new Synth(channel, outs, allSignals, this.voiceParams[channel]));
          }
        } catch (e: any) {
          this.sendMessage({ event: 'log', message: `error loading patch: ${e.message}` });
          console.error(e);
        }
        break;
      }
      case 'process midi message': {
        for (let voice of this.voices) {
          voice.processMidiMessage(msg.data);
        }
        break;
      }
      case 'set curr pattern': {
        this.sequencer.setCurrPattern(msg.pattern);
        break;
      }
      case 'set next pattern': {
        this.sequencer.setNextPattern(msg.pattern);
        break;
      }
      case 'set pattern steps': {
        this.sequencer.setPatternSteps(msg.pattern, msg.steps);
        break;
      }
      case 'set trigger period': {
        this.sequencer.setTriggerPeriod(msg.value);
        break;
      }
      case 'set note duration': {
        this.sequencer.setNoteDuration(msg.value);
        break;
      }
      case 'start sequencer': {
        this.sequencer.start();
        break;
      }
      case 'stop sequencer': {
        this.sequencer.stop();
        break;
      }
      default: {
        console.error('unsupported message', msg);
        throw new Error('unsupported message!');
      }
    }
  }

  private lastAudioErrorAt = 0;
  private static readonly AUDIO_ERROR_COOLDOWN_MS = 2000;

  process(inputs: Float32Array[][], [output]: Float32Array[][], parameters: any) {
    const numFrames = output[0].length;
    try {
      this.sequencer.run(numFrames);
      for (let frameIdx = 0; frameIdx < numFrames; frameIdx++) {
        for (const voice of this.voices) {
          voice.processFrame(inputs, output, frameIdx);
        }
      }
    } catch (e: any) {
      const now = performance.now();
      if (now - this.lastAudioErrorAt >= Msynth.AUDIO_ERROR_COOLDOWN_MS) {
        this.lastAudioErrorAt = now;
        this.sendMessage({
          event: 'log',
          message: `Audio: exception in synth (${e?.message ?? e}). Output muted for this block.`,
        });
      }
      for (let ch = 0; ch < output.length; ch++) {
        output[ch].fill(0);
      }
    }
    return true;
  }
}

class Sequencer {
  state: SequencerState = {
    patternA: [],
    patternB: [],
    currPattern: 'A',
    currStep: 0,
    nextPattern: 'A',
    triggerPeriod: 1 / 4,
    noteDuration: 0.5,
    playing: false,
  };
  measuresSinceLastTrigger = Infinity;

  constructor(public synth: Msynth) { }

  setCurrPattern(pattern: PatternName) {
    this.stop(false); // don't send new state yet
    this.state.currPattern = pattern;
    this.sendNewState();
  }

  setNextPattern(pattern: PatternName) {
    this.state.nextPattern = pattern;
    this.sendNewState();
  }

  setPatternSteps(pattern: PatternName, steps: Pattern) {
    this.stop(false); // don't send new state yet
    if (pattern === 'A') {
      this.state.patternA = steps;
    } else {
      this.state.patternB = steps;
    }
    this.sendNewState();
  }

  setTriggerPeriod(value: number) {
    this.state.triggerPeriod = Math.max(0.01, value);
    this.sendNewState();
  }

  setNoteDuration(value: number) {
    this.state.noteDuration = clamp(value, 0.01, 0.99);
    this.sendNewState();
  }

  start() {
    this.state.playing = true;
    this.state.currStep = 0;
    this.measuresSinceLastTrigger = Infinity;
    this.sendNewState();
  }

  stop(sendNewState: boolean = true) {
    this.playCurrentStep('noteOff');
    this.state.playing = false;
    this.state.currStep = 0;
    if (sendNewState) {
      this.sendNewState();
    }
  }

  private sendNewState() {
    this.synth.sendMessage({ event: 'seq state', state: this.state });
  }

  private notesAreOn = false;
  private channelsUsed: number[] = [];

  private get currPattern() {
    return this.state.currPattern === 'A' ? this.state.patternA : this.state.patternB;
  }

  run(numFrames: number) {
    if (!this.state.playing || this.currPattern.length === 0) {
      return;
    }

    if (this.measuresSinceLastTrigger >= this.state.triggerPeriod) {
      this.playCurrentStep('noteOn');
      this.measuresSinceLastTrigger = 0;
      return;
    }

    if (this.notesAreOn && this.measuresSinceLastTrigger >= this.state.noteDuration * this.state.triggerPeriod) {
      this.playCurrentStep('noteOff');
      this.state.currStep = (this.state.currStep + 1) % this.currPattern.length;
      if (this.state.currStep === 0) {
        this.state.currPattern = this.state.nextPattern;
        this.sendNewState();
      }
    }

    // Convert elapsed samples into "measures" so that:
    // - tempo is in BPM
    // - one measure is 4 quarter-notes (4/4 time)
    // - triggerPeriod is expressed as a fraction of a measure
    //
    // seconds elapsed in this block
    const secondsElapsed = numFrames / SAMPLE_RATE;
    // seconds per measure = 4 * (60 / tempo) = 240 / tempo
    const secondsPerMeasure = 240 / this.synth.voices[0]!.params[P_TEMPO];
    this.measuresSinceLastTrigger += secondsElapsed / secondsPerMeasure;
  }

  private playCurrentStep(action: 'noteOn' | 'noteOff') {
    const notes = this.currPattern[this.state.currStep];
    if (!notes) {
      return;
    }

    if (action === 'noteOn') {
      this.channelsUsed = [];
      this.notesAreOn = true;
    } else {
      this.notesAreOn = false;
    }

    this.synth.sendMessage({ event: 'seq step', pattern: this.state.currPattern, index: this.state.currStep, action });

    notes.forEach((note, idx) => {
      let ch: number;
      if (action === 'noteOn') {
        ch = this.nextVoiceIdx();
        this.channelsUsed.push(ch);
      } else {
        ch = this.channelsUsed[idx];
      }
      this.synth.voices[ch]?.processMidiMessage(
        (action === 'noteOn' ? noteOn : noteOff)(ch, note, 127),
      );
    });
  }

  // TODO: be smarter about allocating voices
  // (Ideally, we should coordinate between here and the UI so that
  // there is as little voice-stealing as possible when the sequencer
  // and the user are playing at the same time.)
  private lastVoiceIdx = -1;
  private nextVoiceIdx() {
    const idx = (this.lastVoiceIdx + 1) % this.synth.voices.length;
    this.lastVoiceIdx = idx;
    return idx;
  }
}

registerProcessor('msynth', Msynth);
