import { Signal } from './signal';
import { clamp, toFrequency } from './helpers';
import { P_GAIN } from './constants';

/** Replace NaN/Infinity with 0 so bad signal math never silences or corrupts the output. */
function sanitizeSample(x: number): number {
  return Number.isFinite(x) ? x : 0;
}

export class Synth {
  noteNums: number[] = [];
  noteNum = 0;
  noteFreq = 0;
  noteVel = 0;

  constructor(
    readonly channel: number,
    readonly outs: Signal[],
    readonly allSignals: Signal[],
    readonly params: Float32Array<any>,
  ) { }

  processMidiMessage([d1, d2, d3]: Uint8Array) {
    const channel = d1 & 0b1111;
    if (channel !== this.channel) {
      return; // this message is not for me, so ignore it
    }

    switch (d1 >> 4) {
      case 0b1001: {
        const note = d2;
        const velocity = d3;
        if (velocity === 0) {
          // some devices send noteOn with vel 0 for noteOff!
          this.noteOff(note, velocity);
        } else {
          this.noteOn(note, velocity);
        }
        break;
      }
      case 0b1000: {
        const note = d2;
        const velocity = d3;
        this.noteOff(note, velocity);
        break;
      }
    }
  }

  noteOn(note: number, vel: number) {
    this.noteNums.push(note);
    this.noteNum = note;
    this.noteFreq = toFrequency(note);
    this.noteVel = vel / 127;
    this.allSignals.forEach((s) => s.noteOn?.(this, false));
  }

  noteOff(note: number, vel: number) {
    const idx = this.noteNums.indexOf(note);
    const retriggerNext = idx === this.noteNums.length - 1;
    this.noteNums.splice(idx, 1);
    const nextNote = this.noteNums.at(-1);
    if (nextNote != null && retriggerNext) {
      this.noteNum = nextNote;
      this.noteFreq = toFrequency(nextNote);
      this.allSignals.forEach((s) => s.noteOn?.(this, true));
    } else if (this.noteNums.length === 0) {
      this.allSignals.forEach((s) => s.noteOff?.());
    }
  }

  processFrame(inputs: Float32Array[][], output: Float32Array[], frameIdx: number) {
    this.allSignals.forEach((s) => s.computeSample(frameIdx, this, inputs));
    const gain = this.params[P_GAIN];
    if (this.outs.length === 2 && output.length >= 2) {
      // stereo
      for (let ch = 0; ch < 2; ch++) {
        const sample = sanitizeSample(this.outs[ch].value * gain);
        output[ch][frameIdx] += sample;
      }
    } else {
      // mono
      const sample = sanitizeSample(this.outs[0].value * gain);
      for (let ch = 0; ch < output.length; ch++) {
        output[ch][frameIdx] += sample;
      }
    }
  }
}
